package com.dayOne;

public class SwapNumber {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a = 10;
		int b = 20;
		
		
		System.out.println("Before Swap : A = "+a+" B = "+b);
		int temp = a;
		a = b;
		b = temp;
		
//		a = a-b;
//		b=b+a;
//		a=b-a;
		
		System.out.println("Before Swap : A = "+a+" B = "+b);

	}

}
